/**
 * useSpring Hook
 *
 * React hook for spring animations with Reanimated.
 */

import { useCallback, useMemo } from 'react';
import {
  useSharedValue,
  useAnimatedStyle,
  withSpring,
  type WithSpringConfig,
  type SharedValue,
} from 'react-native-reanimated';

import { defaultSpring } from '../springs';

/**
 * Spring animation options
 */
interface UseSpringOptions {
  initialValue?: number;
  stiffness?: number;
  damping?: number;
  mass?: number;
  overshootClamping?: boolean;
}

/**
 * Spring animation result
 */
interface UseSpringResult {
  value: SharedValue<number>;
  animatedStyle: ReturnType<typeof useAnimatedStyle>;
  setValue: (target: number, config?: WithSpringConfig) => void;
  reset: () => void;
}

/**
 * Hook for spring animations
 */
export function useSpring(options: UseSpringOptions = {}): UseSpringResult {
  const { initialValue = 0, ...springConfig } = options;
  const config = useMemo(
    () => ({ ...defaultSpring, ...springConfig }),
    [
      springConfig.damping,
      springConfig.mass,
      springConfig.overshootClamping,
      springConfig.stiffness,
    ]
  );

  const value = useSharedValue(initialValue);

  const animatedStyle = useAnimatedStyle(() => {
    return {
      transform: [{ scale: value.value }],
    };
  });

  const setValue = useCallback(
    (target: number, overrideConfig?: WithSpringConfig) => {
      const finalConfig = overrideConfig ? { ...config, ...overrideConfig } : config;
      value.value = withSpring(target, finalConfig as WithSpringConfig);
    },
    [value, config]
  );

  const reset = useCallback(() => {
    value.value = withSpring(initialValue, config as WithSpringConfig);
  }, [value, initialValue, config]);

  return {
    value,
    animatedStyle,
    setValue,
    reset,
  };
}

/**
 * Hook for spring with custom animated style
 */
export function useSpringStyle(
  styleFactory: (val: SharedValue<number>) => ReturnType<typeof useAnimatedStyle>,
  options: UseSpringOptions = {}
): UseSpringResult {
  const { initialValue = 0, ...springConfig } = options;
  const config = useMemo(
    () => ({ ...defaultSpring, ...springConfig }),
    [
      springConfig.damping,
      springConfig.mass,
      springConfig.overshootClamping,
      springConfig.stiffness,
    ]
  );

  const value = useSharedValue(initialValue);
  const animatedStyle = useAnimatedStyle(() => styleFactory(value));

  const setValue = useCallback(
    (target: number, overrideConfig?: WithSpringConfig) => {
      const finalConfig = overrideConfig ? { ...config, ...overrideConfig } : config;
      value.value = withSpring(target, finalConfig as WithSpringConfig);
    },
    [value, config]
  );

  const reset = useCallback(() => {
    value.value = withSpring(initialValue, config as WithSpringConfig);
  }, [value, initialValue, config]);

  return {
    value,
    animatedStyle,
    setValue,
    reset,
  };
}

/**
 * AchievementUnlockToast
 *
 * Toast notification for achievement unlocks.
 * Slides down from top, shows icon + title + rarity.
 * Auto-dismisses with duration based on rarity.
 * Tap to navigate to achievement detail.
 * Haptic feedback on display.
 */

import React, { useEffect, useCallback } from 'react';
import { Pressable, Dimensions } from 'react-native';
import Animated, { useSharedValue, useAnimatedStyle, withSpring, withTiming, withDelay, runOnJS } from 'react-native-reanimated';
import { Box, Text } from '@/components/primitives';
import { useTheme } from '@/theme';
import { achievementUnlocked } from '@/utils/haptics';
import type { Achievement, AchievementRarity } from '../types';
import { getAchievementDisplayInfo, getRarityColor } from '../definitions';

// ============================================================================
// Constants
// ============================================================================

const { width: SCREEN_WIDTH } = Dimensions.get('window');

const DISMISS_DURATIONS: Record<AchievementRarity, number> = {
  COMMON: 3500,
  UNCOMMON: 3500,
  RARE: 3500,
  EPIC: 5000,
  LEGENDARY: 5000,
};

// ============================================================================
// Types
// ============================================================================

interface AchievementUnlockToastProps {
  achievement: Achievement;
  onPress: () => void;
  onDismiss: () => void;
  visible: boolean;
}

// ============================================================================
// Component
// ============================================================================

export const AchievementUnlockToast: React.FC<AchievementUnlockToastProps> = ({ achievement, onPress, onDismiss, visible }) => {
  const { theme } = useTheme();
  const display = getAchievementDisplayInfo(achievement, true);
  const rarityColor = getRarityColor(achievement.rarity);

  const isHighRarity = achievement.rarity === 'EPIC' || achievement.rarity === 'LEGENDARY';

  // Animation values
  const translateY = useSharedValue(-200);
  const opacity = useSharedValue(0);
  const scale = useSharedValue(0.8);
  const glowOpacity = useSharedValue(0);

  // Trigger haptic and entrance animation
  useEffect(() => {
    if (visible) {
      // Haptic feedback for achievement unlock
      void achievementUnlocked();

      // Entrance animation
      translateY.value = withSpring(60, { damping: 15, stiffness: 200 });
      opacity.value = withTiming(1, { duration: 300 });
      scale.value = withSpring(1, { damping: 12, stiffness: 150 });

      // Glow animation for high rarity
      if (isHighRarity) {
        glowOpacity.value = withDelay(500, withTiming(1, { duration: 500 }));
      }

      // Auto-dismiss
      const dismissDuration = DISMISS_DURATIONS[achievement.rarity];
      const timeout = setTimeout(() => {
        handleDismiss();
      }, dismissDuration);

      return () => clearTimeout(timeout);
    } else {
      // Exit animation
      translateY.value = withTiming(-200, { duration: 300 });
      opacity.value = withTiming(0, { duration: 200 });
      scale.value = withTiming(0.8, { duration: 200 });
      return; // Explicit return for else branch
    }
  }, [visible, achievement.rarity]);

  const handleDismiss = useCallback(() => {
    translateY.value = withTiming(-200, { duration: 300 }, () => {
      'worklet';
      runOnJS(onDismiss)();
    });
    opacity.value = withTiming(0, { duration: 200 });
    return; // Explicit return to satisfy all code paths
  }, [onDismiss]);

  const handlePress = useCallback(() => {
    handleDismiss();
    // Small delay to let animation start before navigating
    setTimeout(() => {
      onPress();
    }, 200);
    return; // Explicit return to satisfy all code paths
  }, [handleDismiss, onPress]);

  // Animated styles
  const containerStyle = useAnimatedStyle(() => ({
    transform: [{ translateY: translateY.value }, { scale: scale.value }],
    opacity: opacity.value,
  }));

  const glowStyle = useAnimatedStyle(() => ({
    opacity: glowOpacity.value,
  }));

  if (!visible) {
    return null;
  }

  return (
    <Animated.View
      style={[
        {
          position: 'absolute',
          top: 0,
          left: 16,
          right: 16,
          zIndex: 1000,
        },
        containerStyle,
      ]}
    >
      <Pressable onPress={handlePress} accessibilityLabel="Interactive control" accessibilityRole="button" accessibilityHint="Activates this control">
        {/* Glow effect for EPIC/LEGENDARY */}
        {isHighRarity && (
          <Animated.View
            style={[
              {
                position: 'absolute',
                top: -10,
                left: -10,
                right: -10,
                bottom: -10,
                backgroundColor: rarityColor,
                borderRadius: 24,
              },
              glowStyle,
            ]}
            pointerEvents="none"
          />
        )}

        <Box
          p={isHighRarity ? 5 : 4}
          borderRadius={16}
          bg={theme.colors.background.secondary}
          style={{
            borderWidth: 2,
            borderColor: rarityColor,
            shadowColor: rarityColor,
            shadowOffset: { width: 0, height: 4 },
            shadowOpacity: 0.3,
            shadowRadius: 12,
            elevation: 8,
          }}
        >
          <Box flexDirection="row" alignItems="center" gap={3}>
            {/* Icon */}
            <Box
              width={isHighRarity ? 56 : 48}
              height={isHighRarity ? 56 : 48}
              borderRadius={isHighRarity ? 28 : 24}
              bg={`${rarityColor}25`}
              alignItems="center"
              justifyContent="center"
              style={{
                borderWidth: 2,
                borderColor: rarityColor,
              }}
            >
              <Text style={{ fontSize: isHighRarity ? 32 : 28 }}>{display.icon}</Text>
            </Box>

            {/* Content */}
            <Box flex={1}>
              <Text variant="caption" color={rarityColor} fontWeight="bold" mb={1}>
                🏆 ACHIEVEMENT UNLOCKED
              </Text>
              <Text variant={isHighRarity ? 'h4' : 'body'} color={theme.colors.text.primary} fontWeight="semibold" numberOfLines={1}>
                {display.title}
              </Text>
            </Box>

            {/* Rarity Badge */}
            <Box px={3} py={1} borderRadius={8} style={{ backgroundColor: `${rarityColor}30` }}>
              <Text variant="caption" color={rarityColor} fontWeight="bold">
                {achievement.rarity}
              </Text>
            </Box>
          </Box>

          {/* Extra flair for LEGENDARY */}
          {achievement.rarity === 'LEGENDARY' && (
            <Box mt={3} alignItems="center">
              <Text variant="caption" color={theme.colors.warning.DEFAULT}>
                ✨ LEGENDARY RARITY ✨
              </Text>
            </Box>
          )}
        </Box>
      </Pressable>
    </Animated.View>
  );
};

// ============================================================================
// Toast Manager Hook
// ============================================================================

/**
 * Hook to manage achievement unlock toasts
 * Listens to achievement:unlocked events and shows toasts
 */
export function useAchievementUnlockToast(
  userId: string,
  onAchievementPress: (achievementId: string) => void,
): {
  currentToast: Achievement | null;
  dismissToast: () => void;
} {
  const [currentToast, setCurrentToast] = React.useState<Achievement | null>(null);
  const toastQueue = React.useRef<Achievement[]>([]);

  // Listen for achievement unlock events
  React.useEffect(() => {
    // Subscribe to achievement:unlocked event
    const handleUnlock = (event: { userId: string; achievementId: string; unlockedAt: number }) => {
      if (event.userId !== userId) {
        return;
      }

      // Get achievement details
      const { getAchievementById } = require('../definitions');
      const achievement = getAchievementById(event.achievementId);
      if (!achievement) {
        return;
      }

      // Add to queue
      toastQueue.current.push(achievement);

      // Show toast if none currently visible
      if (!currentToast) {
        showNextToast();
      }
    };

    // In a real app, subscribe to event bus
    // const unsubscribe = eventBus.subscribe('achievement:unlocked', handleUnlock);

    return () => {
      // unsubscribe();
    };
  }, [userId, currentToast]);

  const showNextToast = React.useCallback(() => {
    const nextAchievement = toastQueue.current.shift();
    if (nextAchievement) {
      setCurrentToast(nextAchievement);
    }
  }, []);

  const dismissToast = React.useCallback(() => {
    setCurrentToast(null);
    // Show next toast after a short delay
    setTimeout(() => {
      showNextToast();
    }, 300);
  }, [showNextToast]);

  const handlePress = React.useCallback(() => {
    if (currentToast) {
      onAchievementPress(currentToast.id);
    }
    dismissToast();
  }, [currentToast, onAchievementPress, dismissToast]);

  return {
    currentToast,
    dismissToast,
  };
}

// ============================================================================
// Provider Component
// ============================================================================

interface AchievementToastProviderProps {
  children: React.ReactNode;
  userId: string;
  onAchievementPress: (achievementId: string) => void;
}

export const AchievementToastProvider: React.FC<AchievementToastProviderProps> = ({ children, userId, onAchievementPress }) => {
  const { currentToast, dismissToast } = useAchievementUnlockToast(userId, onAchievementPress);

  return (
    <Box flex={1}>
      {children}
      {currentToast && <AchievementUnlockToast achievement={currentToast} onPress={() => onAchievementPress(currentToast.id)} onDismiss={dismissToast} visible={!!currentToast} />}
    </Box>
  );
};

// ============================================================================
// Export
// ============================================================================

export default AchievementUnlockToast;

/**
 * Coach Screen
 *
 * Phase 9.3 — Dedicated coach UI with chat-like layout
 * Accessible from home screen, not just push notifications
 */

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { View, Text, TextInput, Pressable, ActivityIndicator, KeyboardAvoidingView, Platform, SafeAreaView, Image } from 'react-native';
import { FlashList, type FlashListRef, type ListRenderItem } from '@shopify/flash-list';
import { useAnalytics } from '@/shared/analytics';
import { CoachEvents } from '@/shared/analytics/analytics-events';

import { getCurrentRecommendation } from '../services/coach-screen-service';
import type { CoachMessage, CoachState, CoachUserState } from '../types';
import { PERSONALITY_METADATA } from '../service/personality-templates';
import { useAskCoachQuestionMutation, useCoachScreenState } from '../hooks';
import { styles } from './CoachScreen.styles';

// ============================================================================
// Types
// ============================================================================

interface ChatMessage {
  id: string;
  type: 'coach' | 'user' | 'system';
  content: string;
  timestamp: number;
  metadata?: {
    state?: CoachUserState;
    hasAction?: boolean;
    actionLabel?: string;
    actionData?: Record<string, unknown>;
  };
}

interface CoachRecommendation {
  duration: number;
  difficulty: string;
  reasoning: string;
}

export function CoachScreen(): JSX.Element {
  const { track } = useAnalytics();
  const flashListRef = useRef<FlashListRef<ChatMessage> | null>(null);

  // State
  const [inputText, setInputText] = useState('');
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [isTyping, setIsTyping] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const { coachState, coachHistory, stateLoading, historyLoading } = useCoachScreenState();

  const askMutation = useAskCoachQuestionMutation({
    onMutate: () => {
      setIsTyping(true);
      setError(null);
    },
    onSuccess: (response) => {
      setIsTyping(false);
      const coachMsg: ChatMessage = {
        id: `coach-${Date.now()}`,
        type: 'coach',
        content: response.message,
        timestamp: Date.now(),
        metadata: {
          hasAction: response.hasAction,
          actionLabel: response.actionLabel,
          actionData: response.actionData,
        },
      };

      setChatMessages((prev) => [...prev, coachMsg]);
      track(CoachEvents.COACH_QUESTION_ANSWERED, {
        has_action: response.hasAction,
      } as Record<string, unknown>);
    },
    onError: (message) => {
      setIsTyping(false);
      setError(message);
    },
  });

  // Initialize chat messages from history
  useEffect(() => {
    if (coachHistory?.messages && chatMessages.length === 0) {
      const initialMessages: ChatMessage[] = coachHistory.messages
        .slice(-20) // Last 20 messages
        .map((msg) => ({
          id: msg.id,
          type: (msg as unknown as { sender?: string }).sender === 'user' ? 'user' : 'coach',
          content: msg.content,
          timestamp: msg.createdAt,
          metadata: (msg as unknown as { metadata?: Record<string, unknown> }).metadata,
        }));

      // Add welcome message if empty
      if (initialMessages.length === 0) {
        initialMessages.push({
          id: 'welcome',
          type: 'coach',
          content: getWelcomeMessage(coachState),
          timestamp: Date.now(),
          metadata: { state: coachState?.currentState },
        });
      }

      setChatMessages(initialMessages);
    }
  }, [coachHistory, coachState]);

  // Scroll to bottom when new messages arrive
  useEffect(() => {
    if (chatMessages.length > 0) {
      setTimeout(() => {
        flashListRef.current?.scrollToEnd({ animated: true });
      }, 100);
    }
  }, [chatMessages]);

  // Handle send message
  const handleSend = useCallback(() => {
    if (!inputText.trim()) {
      return;
    }

    const question = inputText.trim();

    // Add user message to chat
    const userMsg: ChatMessage = {
      id: `user-${Date.now()}`,
      type: 'user',
      content: question,
      timestamp: Date.now(),
    };

    setChatMessages((prev) => [...prev, userMsg]);
    setInputText('');

    // Track analytics
    track(CoachEvents.COACH_QUESTION_ASKED, {
      question: question.substring(0, 50),
    } as Record<string, unknown>);

    // Send to coach
    askMutation.mutate(question);
  }, [inputText, askMutation, track]);

  // Handle action button press
  const handleActionPress = useCallback(
    (message: ChatMessage) => {
      if (!message.metadata?.actionData) {
        return;
      }

      const action = message.metadata.actionData;

      // Handle different action types
      switch (action.type) {
        case 'START_SESSION':
          // Navigate to session with pre-filled config
          // This would integrate with navigation
          track(CoachEvents.COACH_CTA_CLICKED, {
            cta_type: 'start_session',
            session_duration: action.duration as number,
          });
          break;

        case 'VIEW_STREAK':
          // Navigate to streak screen
          track(CoachEvents.COACH_CTA_CLICKED, {
            cta_type: 'view_streak',
          });
          break;

        case 'VIEW_PROGRESS':
          // Navigate to progression
          track(CoachEvents.COACH_CTA_CLICKED, {
            cta_type: 'view_progress',
          });
          break;

        default:
          break;
      }
    },
    [track],
  );

  // Render chat message
  const renderMessage: ListRenderItem<ChatMessage> = useCallback(
    ({ item }) => {
      const isCoach = item.type === 'coach';
      const isUser = item.type === 'user';

      return (
        <View style={[styles.messageContainer, isCoach ? styles.coachMessageContainer : isUser ? styles.userMessageContainer : styles.systemMessageContainer]}>
          {isCoach && (
            <View style={styles.coachAvatar}>
              <Text style={styles.coachAvatarText}>{getPersonalityEmoji(coachState?.personaId)}</Text>
            </View>
          )}

          <View style={[styles.messageBubble, isCoach ? styles.coachBubble : isUser ? styles.userBubble : styles.systemBubble]}>
            <Text style={[styles.messageText, isCoach ? styles.coachText : isUser ? styles.userText : styles.systemText]}>{item.content}</Text>

            {/* Action Button */}
            {item.metadata?.hasAction && item.metadata.actionLabel && (
              <Pressable style={({ pressed }) => [styles.actionButton, pressed && { opacity: 0.8 }]} onPress={() => handleActionPress(item)} accessibilityLabel="Action button" accessibilityRole="button" accessibilityHint="Activates this control">
                <Text style={styles.actionButtonText}>{item.metadata.actionLabel}</Text>
              </Pressable>
            )}
          </View>
        </View>
      );
    },
    [coachState?.personaId, handleActionPress],
  );

  // Loading state
  if (stateLoading || historyLoading) {
    return (
      <SafeAreaView style={styles.container}>
        <View style={{ height: 44 }} />
        <View style={styles.loadingContainer}>
          <ActivityIndicator size="large" color="#6366f1" />
          <Text style={styles.loadingText}>Loading your coach...</Text>
        </View>
      </SafeAreaView>
    );
  }

  // Get current recommendation
  // Recommendation computed from state - fix type mismatch
  const recommendation = coachState ? getCurrentRecommendation(coachState) : null;

  return (
    <SafeAreaView style={styles.container}>
      <View style={{ height: 44 }} />

      {/* Header */}
      <View style={styles.header}>
        <View style={styles.coachInfo}>
          <Text style={styles.coachName}>{getPersonalityName(coachState?.personaId)}</Text>
          <View style={styles.statusBadge}>
            <Text style={styles.statusText}>{formatState(coachState?.currentState)}</Text>
          </View>
        </View>

        {/* State Indicator */}
        <View style={styles.stateIndicator}>
          <View style={[styles.stateDot, { backgroundColor: getStateColor(coachState?.currentState) }]} />
          <Text style={styles.stateLabel}>Active</Text>
        </View>
      </View>

      {/* Session Recommendation Card */}
      {recommendation && (
        <View style={styles.recommendationCard}>
          <Text style={styles.recommendationTitle}>Recommended Session</Text>
          <Text style={styles.recommendationReason}>{recommendation.reasoning}</Text>
          <Pressable
            style={({ pressed }) => [styles.startSessionButton, pressed && { opacity: 0.8 }]}
            onPress={() => {
              track(CoachEvents.COACH_CTA_CLICKED, {
                duration: recommendation.duration,
                difficulty: recommendation.difficulty,
                source: 'coach_recommendation',
              });
              // Navigate to session setup
            }}
            accessibilityLabel="Start session button"
            accessibilityRole="button"
            accessibilityHint="Activates this control"
          >
            <Text style={styles.startSessionButtonText}>Start {recommendation.duration}-min Session</Text>
          </Pressable>
        </View>
      )}

      {/* Chat Area */}
      <KeyboardAvoidingView style={styles.chatContainer} behavior={Platform.OS === 'ios' ? 'padding' : 'height'} keyboardVerticalOffset={Platform.OS === 'ios' ? 90 : 0}>
        <FlashList
          ref={flashListRef}
          data={chatMessages}
          renderItem={renderMessage}
          keyExtractor={(item: ChatMessage) => item.id}
          contentContainerStyle={styles.chatContent}
          showsVerticalScrollIndicator={true}
          estimatedItemSize={80}
          onContentSizeChange={() => {
            flashListRef.current?.scrollToEnd({ animated: false });
          }}
        />

        {/* Typing Indicator */}
        {isTyping && (
          <View style={styles.typingContainer}>
            <View style={styles.coachAvatarSmall}>
              <Text style={styles.coachAvatarTextSmall}>{getPersonalityEmoji(coachState?.personaId)}</Text>
            </View>
            <View style={styles.typingBubble}>
              <ActivityIndicator size="small" color="#6366f1" />
              <Text style={styles.typingText}>Thinking...</Text>
            </View>
          </View>
        )}

        {/* Error Banner */}
        {error && (
          <View style={styles.errorBanner}>
            <Text style={styles.errorText}>{error}</Text>
            <Pressable onPress={() => setError(null)} style={({ pressed }) => [pressed && { opacity: 0.8 }]} accessibilityLabel="Dismiss button" accessibilityRole="button" accessibilityHint="Activates this control">
              <Text style={styles.errorDismiss}>Dismiss</Text>
            </Pressable>
          </View>
        )}

        {/* Input Area */}
        <View style={styles.inputContainer}>
          <TextInput style={styles.input} value={inputText} onChangeText={setInputText} placeholder="Ask your coach anything..." placeholderTextColor="#9ca3af" multiline maxLength={200} onSubmitEditing={handleSend} returnKeyType="send" />
          <Pressable style={({ pressed }) => [styles.sendButton, !inputText.trim() && styles.sendButtonDisabled, pressed && { opacity: 0.8 }]} onPress={handleSend} disabled={!inputText.trim() || isTyping} accessibilityLabel="Send button" accessibilityRole="button" accessibilityHint="Activates this control">
            <Text style={styles.sendButtonText}>Send</Text>
          </Pressable>
        </View>
      </KeyboardAvoidingView>
    </SafeAreaView>
  );
}

// ============================================================================
// Helper Functions
// ============================================================================

function getWelcomeMessage(coachState?: CoachState | null): string {
  if (!coachState) {
    return "Hi! I'm your AI coach. I'm here to help you build focus habits and achieve your goals. What would you like to work on today?";
  }

  switch (coachState.currentState) {
    case 'COLD_START':
      return "Welcome! I'm your AI coach. I can see you're just getting started — that's exciting! Let's build some momentum together. What brings you here today?";

    case 'HIGH_CONFIDENCE':
      return "You're on fire! 🔥 I can see your consistency is paying off. What can I help you with today?";

    case 'STREAK_AT_RISK':
      return "I noticed your streak needs attention soon. Don't worry — I've got your back. Want to protect it together?";

    case 'COMEBACK_MODE':
      return 'Welcome back! 💪 Every master was once a beginner who returned. Your comeback starts now. How can I support you?';

    case 'POST_FAILURE_SUPPORT':
      return "Hey, I saw things didn't go as planned recently. That's okay — setbacks are part of growth. Let's talk about what happened and how to move forward.";

    default:
      return "Hi there! Ready to make today count? I'm here to help with sessions, streaks, or just a motivational boost.";
  }
}

function getPersonalityName(personaId?: string | null): string {
  if (!personaId) {
    return 'Coach';
  }
  return PERSONALITY_METADATA[personaId as keyof typeof PERSONALITY_METADATA]?.name || 'Coach';
}

function getPersonalityEmoji(personaId?: string | null): string {
  if (!personaId) {
    return '🎯';
  }

  switch (personaId) {
    case 'DRILL_SERGEANT':
      return '⭐';
    case 'FRIEND':
      return '🤗';
    case 'MENTOR':
      return '📚';
    case 'RIVAL':
      return '⚡';
    case 'MINDFUL':
      return '🧘';
    default:
      return '🎯';
  }
}

function formatState(state?: CoachUserState | null): string {
  if (!state) {
    return 'Ready';
  }

  const stateLabels: Record<CoachUserState, string> = {
    COLD_START: 'Getting Started',
    LOW_CONFIDENCE: 'Building Confidence',
    HIGH_CONFIDENCE: 'In The Zone',
    STREAK_AT_RISK: 'Streak Alert',
    COMEBACK_MODE: 'Comeback',
