/**
 * CompanionEvolutionCeremony
 *
 * PHASE 13.2 - Full-screen ceremony for companion evolution
 * 4-phase animated ceremony when companion reaches next evolution phase
 *
 * @phase 13.2
 */

import React, { useEffect, useState } from 'react';
import { Dimensions, Pressable } from 'react-native';
import Animated, { useSharedValue, useAnimatedStyle, withTiming, withSpring, withSequence, withDelay, interpolate, Easing, runOnJS } from 'react-native-reanimated';

import { Box, Text } from '../../../components/primitives';
import { useTheme } from '../../../theme';
import type { CompanionState, CompanionPhase } from '../types';
import { ELEMENT_THEMES, EVOLUTION_THRESHOLDS } from '../types';

const { width: SCREEN_WIDTH, height: SCREEN_HEIGHT } = Dimensions.get('window');

type EvolutionPhase = 'energy-buildup' | 'flash' | 'transformation' | 'celebration' | 'complete';

interface CompanionEvolutionCeremonyProps {
  /** Companion state BEFORE evolution */
  previousState: CompanionState;
  /** New phase after evolution */
  newPhase: CompanionPhase;
  /** Called when ceremony completes */
  onComplete: () => void;
}

// Phase display names
const PHASE_NAMES: Record<CompanionPhase, string> = {
  EGG: 'Egg',
  HATCHING: 'Hatching',
  YOUNG: 'Young',
  MATURE: 'Mature',
  AWAKENED: 'Awakened',
  TRANSCENDENT: 'Transcendent',
};

// Phase emojis
const PHASE_EMOJIS: Record<CompanionPhase, string> = {
  EGG: '🥚',
  HATCHING: '🐣',
  YOUNG: '🐤',
  MATURE: '🦅',
  AWAKENED: '🐉',
  TRANSCENDENT: '🌟',
};

export const CompanionEvolutionCeremony: React.FC<CompanionEvolutionCeremonyProps> = ({ previousState, newPhase, onComplete }) => {
  const { theme } = useTheme();
  const [ceremonyPhase, setCeremonyPhase] = useState<EvolutionPhase>('energy-buildup');

  // Animation values
  const glowOpacity = useSharedValue(0.3);
  const glowScale = useSharedValue(1);
  const flashOpacity = useSharedValue(0);
  const oldFormOpacity = useSharedValue(1);
  const oldFormScale = useSharedValue(1);
  const newFormOpacity = useSharedValue(0);
  const newFormScale = useSharedValue(0.5);
  const textOpacity = useSharedValue(0);
  const textScale = useSharedValue(0.8);
  const particleBurst = useSharedValue(0);

  const themeColors = ELEMENT_THEMES[previousState.element];

  // Run ceremony sequence
  useEffect(() => {
    runCeremony();
  }, []);

  const runCeremony = async () => {
    // Phase 1: Energy Buildup (1 second)
    setCeremonyPhase('energy-buildup');
    glowOpacity.value = withTiming(1, { duration: 1000, easing: Easing.inOut(Easing.sin) });
    glowScale.value = withTiming(2, { duration: 1000, easing: Easing.inOut(Easing.sin) });

    await delay(1000);

    // Phase 2: Flash (0.5 seconds)
    setCeremonyPhase('flash');
    flashOpacity.value = withTiming(1, { duration: 250 });
    oldFormOpacity.value = withTiming(0, { duration: 250 });

    await delay(250);

    flashOpacity.value = withTiming(0, { duration: 250 });

    await delay(250);

    // Phase 3: Transformation (2 seconds)
    setCeremonyPhase('transformation');
    newFormOpacity.value = withTiming(1, { duration: 1000 });
    newFormScale.value = withSpring(1, { damping: 12, stiffness: 100 });
    particleBurst.value = withTiming(1, { duration: 1500, easing: Easing.out(Easing.exp) });

    await delay(2000);

    // Phase 4: Celebration (1 second)
    setCeremonyPhase('celebration');
    textOpacity.value = withTiming(1, { duration: 500 });
    textScale.value = withSpring(1, { damping: 10, stiffness: 200 });

    await delay(1000);

    // Complete
    setCeremonyPhase('complete');
  };

  const handleTap = () => {
    if (ceremonyPhase === 'complete') {
      onComplete();
    }
  };

  // Animated styles
  const glowStyle = useAnimatedStyle(() => ({
    opacity: glowOpacity.value,
    transform: [{ scale: glowScale.value }],
  }));

  const flashStyle = useAnimatedStyle(() => ({
    opacity: flashOpacity.value,
  }));

  const oldFormStyle = useAnimatedStyle(() => ({
    opacity: oldFormOpacity.value,
    transform: [{ scale: oldFormScale.value }],
  }));

  const newFormStyle = useAnimatedStyle(() => ({
    opacity: newFormOpacity.value,
    transform: [{ scale: newFormScale.value }],
  }));

  const textStyle = useAnimatedStyle(() => ({
    opacity: textOpacity.value,
    transform: [{ scale: textScale.value }],
  }));

  const particleStyle = useAnimatedStyle(() => ({
    opacity: interpolate(particleBurst.value, [0, 0.3, 1], [1, 1, 0]),
    transform: [{ scale: interpolate(particleBurst.value, [0, 1], [0.5, 3]) }, { rotate: `${particleBurst.value * 360}deg` }],
  }));

  return (
    <Pressable onPress={handleTap} style={{ flex: 1 }} accessibilityLabel="Interactive control" accessibilityRole="button" accessibilityHint="Activates this control">
      <Box flex={1} alignItems="center" justifyContent="center" bg={theme.colors.background.primary} style={{ position: 'relative' }}>
        {/* Ambient glow background */}
        <Animated.View
          style={[
            {
              position: 'absolute',
              width: SCREEN_WIDTH,
              height: SCREEN_HEIGHT,
              backgroundColor: `${themeColors.glow}30`,
            },
            glowStyle,
          ]}
          pointerEvents="none"
        />

        {/* Energy orb glow */}
        {(ceremonyPhase === 'energy-buildup' || ceremonyPhase === 'flash') && (
          <Animated.View
            style={[
              {
                position: 'absolute',
                width: 200,
                height: 200,
                borderRadius: 100,
                backgroundColor: themeColors.glow,
              },
              glowStyle,
            ]}
            pointerEvents="none"
          />
        )}

        {/* White flash overlay */}
        <Animated.View
          style={[
            {
              position: 'absolute',
              top: 0,
              left: 0,
              right: 0,
              bottom: 0,
              backgroundColor: '#FFFFFF',
              zIndex: 50,
            },
            flashStyle,
          ]}
          pointerEvents="none"
        />

        {/* Old form (fading out) */}
        {(ceremonyPhase === 'energy-buildup' || ceremonyPhase === 'flash') && (
          <Animated.View style={[oldFormStyle, { position: 'absolute', zIndex: 10 }]}>
            <Box alignItems="center">
              <Box
                width={160}
                height={160}
                borderRadius={80}
                bg={`${themeColors.primary}40`}
                justifyContent="center"
                alignItems="center"
                style={{
                  borderWidth: 4,
                  borderColor: themeColors.primary,
                  shadowColor: themeColors.glow,
                  shadowOffset: { width: 0, height: 0 },
                  shadowOpacity: 0.8,
                  shadowRadius: 20,
                }}
              >
                <Text fontSize={72}>{PHASE_EMOJIS[previousState.phase]}</Text>
              </Box>
              <Text variant="h3" color={themeColors.primary} mt={4}>
                {PHASE_NAMES[previousState.phase]}
              </Text>
            </Box>
          </Animated.View>
        )}

        {/* New form (appearing) */}
        {(ceremonyPhase === 'transformation' || ceremonyPhase === 'celebration' || ceremonyPhase === 'complete') && (
          <Animated.View style={[newFormStyle, { position: 'absolute', zIndex: 20 }]}>
            <Box alignItems="center">
              <Box
                width={180}
                height={180}
                borderRadius={90}
                bg={`${themeColors.primary}50`}
                justifyContent="center"
                alignItems="center"
                style={{
                  borderWidth: 6,
                  borderColor: themeColors.glow,
                  shadowColor: themeColors.glow,
                  shadowOffset: { width: 0, height: 0 },
                  shadowOpacity: 1,
                  shadowRadius: 30,
                }}
              >
                <Text fontSize={80}>{PHASE_EMOJIS[newPhase]}</Text>
              </Box>
            </Box>
          </Animated.View>
        )}

        {/* Particle burst effect */}
        {ceremonyPhase === 'transformation' && (
          <Animated.View
            style={[
              {
                position: 'absolute',
                width: 300,
                height: 300,
              },
              particleStyle,
            ]}
            pointerEvents="none"
          >
            {Array.from({ length: 12 }).map((_, i) => {
              const angle = (i / 12) * Math.PI * 2;
              const distance = 100;
              return (
                <Box
                  key={i}
                  position="absolute"
                  width={8}
                  height={8}
                  borderRadius="full"
                  bg={themeColors.particle}
                  style={{
                    left: 150 + Math.cos(angle) * distance - 4,
                    top: 150 + Math.sin(angle) * distance - 4,
                  }}
                />
              );
            })}
          </Animated.View>
        )}

        {/* Celebration text */}
        {(ceremonyPhase === 'celebration' || ceremonyPhase === 'complete') && (
          <Animated.View style={[textStyle, { position: 'absolute', bottom: 120, zIndex: 30 }]}>
            <Box alignItems="center" gap="sm">
              <Text
                variant="hero"
                style={{
                  fontSize: 48,
                  color: themeColors.glow,
                  textShadowColor: themeColors.primary,
                  textShadowOffset: { width: 0, height: 4 },
                  textShadowRadius: 10,
                }}
              >
                EVOLVED!
              </Text>
              <Text variant="h3" color={themeColors.primary}>
                {PHASE_NAMES[newPhase]} Form Unlocked
              </Text>
              <Text variant="body" color="text.secondary" textAlign="center" mt="xs">
                Your companion has grown through {Math.floor(previousState.totalFocusMinutes)} minutes of focused time together.
              </Text>
            </Box>
          </Animated.View>
        )}

        {/* Tap to continue hint */}
        {ceremonyPhase === 'complete' && (
          <Box position="absolute" bottom={40} alignItems="center" zIndex={40}>
            <Text variant="caption" color="text.tertiary">
              Tap anywhere to continue
            </Text>
          </Box>
        )}

        {/* Phase indicator dots at bottom */}
        <Box position="absolute" bottom={80} flexDirection="row" gap="sm" zIndex={35}>
          {(['energy-buildup', 'flash', 'transformation', 'celebration'] as EvolutionPhase[]).map((phase, index) => {
            const isActive = ceremonyPhase === phase || (ceremonyPhase === 'complete' && phase === 'celebration');
            const isPast = ceremonyPhase !== 'complete' && ['transformation', 'celebration', 'complete'].includes(ceremonyPhase) && ['energy-buildup', 'flash'].includes(phase);

            return <Box key={phase} width={8} height={8} borderRadius="full" bg={isActive ? themeColors.primary : isPast ? themeColors.glow : 'background.tertiary'} style={{ opacity: isActive || isPast ? 1 : 0.4 }} />;
          })}
        </Box>
      </Box>
    </Pressable>
  );
};

// Utility function for delays
const delay = (ms: number): Promise<void> => {
  return new Promise((resolve) => setTimeout(resolve, ms));
};

export default CompanionEvolutionCeremony;

/**
 * Living Companion Visual Component
 *
 * A living, breathing entity that evolves in real-time during focus sessions.
 * Uses particle systems, morphing shapes, and ambient animations to create
 * emotional connection and immediate feedback.
 */

import React, { useEffect, useRef, useCallback } from 'react';
import { View, StyleSheet, Dimensions } from 'react-native';
import Animated, { useSharedValue, useAnimatedStyle, withSpring, withRepeat, withTiming, withSequence, interpolate, Easing, runOnJS, useAnimatedReaction, type SharedValue } from 'react-native-reanimated';
import { Svg, Circle, RadialGradient, Stop, G } from 'react-native-svg';

import { Text } from '../../../components/primitives/Text';
import { CompanionState, CompanionPhase, CompanionMood, CompanionElement, ELEMENT_THEMES } from '../types';
import { getCompanionService, CompanionService } from '../service';
import { createSheet } from '@/shared/ui/create-sheet';

const { width: SCREEN_WIDTH, height: SCREEN_HEIGHT } = Dimensions.get('window');
const COMPANION_SIZE = Math.min(SCREEN_WIDTH * 0.6, 300);
const PARTICLE_COUNT = 12;

interface LivingCompanionProps {
  companionState: CompanionState;
  sessionProgress: number; // 0-100
  purityScore: number; // 0-100
  elapsedSeconds: number;
  totalSeconds: number;
  isPaused: boolean;
  onMilestone?: (milestone: number) => void;
}

export const LivingCompanion: React.FC<LivingCompanionProps> = ({ companionState, sessionProgress, purityScore, elapsedSeconds, totalSeconds, isPaused, onMilestone }) => {
  const serviceRef = useRef<CompanionService | null>(null);

  // Animated values for smooth transitions
  const progress = useSharedValue(0);
  const energy = useSharedValue(0);
  const scale = useSharedValue(1);
  const pulsePhase = useSharedValue(0);
  const glowIntensity = useSharedValue(0.5);
  const particlePhase = useSharedValue(0);
  const moodTransition = useSharedValue(0);

  // Initialize service
  useEffect(() => {
    serviceRef.current = getCompanionService(companionState);
    serviceRef.current.startSession(totalSeconds / 60);

    const unsubscribe = serviceRef.current.onEvent((event) => {
      if (event.type === 'MILESTONE' && event.data.progressDelta && onMilestone) {
        onMilestone(event.data.progressDelta);
      }

      if (event.type === 'PURE_FOCUS_BURST') {
        // Trigger burst animation
        scale.value = withSequence(withSpring(1.3, { damping: 10 }), withSpring(1, { damping: 15 }));
        glowIntensity.value = withSequence(withTiming(1, { duration: 200 }), withTiming(0.7, { duration: 1000 }));
      }

      if (event.type === 'DANGER_WARN') {
        scale.value = withRepeat(withSequence(withSpring(0.95, { damping: 5 }), withSpring(1.05, { damping: 5 })), 3);
      }
    });

    return () => {
      unsubscribe();
    };
  }, []);

  // Update service on each tick
  useEffect(() => {
    if (serviceRef.current && !isPaused) {
      serviceRef.current.tick(elapsedSeconds, totalSeconds, purityScore, isPaused);
    }
  }, [elapsedSeconds, purityScore, isPaused]);

  // Animate progress smoothly
  useEffect(() => {
    progress.value = withSpring(sessionProgress / 100, { damping: 20 });
    energy.value = withSpring(purityScore / 100, { damping: 15 });
  }, [sessionProgress, purityScore]);

  // Continuous animations
  useEffect(() => {
    // Breathing animation
    pulsePhase.value = withRepeat(withTiming(1, { duration: 3000, easing: Easing.inOut(Easing.sin) }), -1, true);

    // Particle rotation
    particlePhase.value = withRepeat(withTiming(1, { duration: 10000, easing: Easing.linear }), -1, false);
  }, []);

  // Calculate derived values
  const theme = ELEMENT_THEMES[companionState.element];
  const phaseMultiplier = getPhaseMultiplier(companionState.phase);

  // Animated styles
  const companionStyle = useAnimatedStyle(() => {
    const breathing = interpolate(pulsePhase.value, [0, 1], [0.98, 1.02]);
    const energyPulse = interpolate(energy.value, [0, 1], [0.95, 1.1]);

    return {
      transform: [{ scale: scale.value * breathing * energyPulse }],
      opacity: interpolate(energy.value, [0, 0.2], [0.3, 1]),
    };
  });

  const glowStyle = useAnimatedStyle(() => {
    return {
      opacity: interpolate(glowIntensity.value, [0, 1], [0.2, 0.8]),
      transform: [{ scale: interpolate(pulsePhase.value, [0, 1], [1, 1.2]) }],
    };
  });

  const particleContainerStyle = useAnimatedStyle(() => {
    return {
      transform: [{ rotate: `${particlePhase.value * 360}deg` }],
    };
  });

  const renderParticle = useCallback(
    (index: number) => {
      const angle = (index / PARTICLE_COUNT) * Math.PI * 2;
      const distance = COMPANION_SIZE * 0.6 + (index % 3) * 20;
      const x = Math.cos(angle) * distance;
      const y = Math.sin(angle) * distance;
      const size = 4 + (index % 4) * 2;

      return (
        <Animated.View
          key={index}
          style={[
            styles.particle,
            {
              width: size,
              height: size,
              backgroundColor: theme.particle,
              left: COMPANION_SIZE / 2 + x - size / 2,
              top: COMPANION_SIZE / 2 + y - size / 2,
              opacity: 0.6 + (index % 3) * 0.15,
            },
          ]}
        />
      );
    },
    [theme],
  );

  return (
    <View style={styles.container}>
      {/* Ambient glow background */}
      <Animated.View
        style={[
          styles.glowContainer,
          glowStyle,
          {
            backgroundColor: theme.glow,
            width: COMPANION_SIZE * 1.5,
            height: COMPANION_SIZE * 1.5,
            borderRadius: COMPANION_SIZE * 0.75,
          },
        ]}
      />

      {/* Particle orbit */}
      <Animated.View style={[styles.particleOrbit, particleContainerStyle]}>{Array.from({ length: PARTICLE_COUNT }, (_, i) => renderParticle(i))}</Animated.View>

      {/* Main companion form */}
      <Animated.View style={[styles.companionContainer, companionStyle]}>
        <Svg width={COMPANION_SIZE} height={COMPANION_SIZE}>
          <G>
            {/* Core body - morphs based on phase */}
            <CompanionBody phase={companionState.phase} progress={progress} energy={energy} theme={theme} size={COMPANION_SIZE} />

            {/* Inner light */}
            <Circle cx={COMPANION_SIZE / 2} cy={COMPANION_SIZE / 2} r={COMPANION_SIZE * 0.15 * phaseMultiplier} fill={theme.primary} opacity={0.9} />
          </G>
        </Svg>
      </Animated.View>

      {/* Status indicator */}
      <View style={styles.statusContainer}>
        <Text variant="bodySmall" style={[styles.moodText, { color: theme.primary }]}>
          {getMoodEmoji(companionState.currentMood)} {companionState.currentMood}
        </Text>
        <Text variant="caption" style={styles.phaseText}>
          {companionState.phase} Level {companionState.level}
        </Text>
      </View>
    </View>
  );
};

/**
 * Companion body shape - morphs based on evolution phase
 */
const CompanionBody: React.FC<{
  phase: CompanionPhase;
  progress: SharedValue<number>;
  energy: SharedValue<number>;
  theme: { primary: string; secondary: string; glow: string };
  size: number;
}> = ({ phase, theme, size }) => {
  const radius = size * 0.4;
  const center = size / 2;

  // Different shapes for different phases
  const renderPhaseShape = () => {
    switch (phase) {
      case 'EGG':
        // Simple egg shape
        return (
          <>
            <RadialGradient id="eggGradient" cx={center} cy={center} rx={radius} ry={radius * 1.2}>
              <Stop offset="0%" stopColor={theme.primary} stopOpacity="0.8" />
              <Stop offset="100%" stopColor={theme.secondary} stopOpacity="0.3" />
            </RadialGradient>
            <Circle cx={center} cy={center} r={radius} fill="url(#eggGradient)" />
          </>
        );

      case 'HATCHING':
        // Cracked egg with emerging form
        return (
          <>
            <RadialGradient id="hatchGradient" cx={center} cy={center} rx={radius} ry={radius}>
              <Stop offset="0%" stopColor={theme.glow} stopOpacity="0.9" />
              <Stop offset="60%" stopColor={theme.primary} stopOpacity="0.6" />
              <Stop offset="100%" stopColor={theme.secondary} stopOpacity="0.2" />
            </RadialGradient>
            <Circle cx={center} cy={center} r={radius} fill="url(#hatchGradient)" />
            {/* Crack lines */}
            <Circle cx={center - radius * 0.3} cy={center - radius * 0.2} r={2} fill={theme.primary} />
            <Circle cx={center + radius * 0.2} cy={center + radius * 0.3} r={1.5} fill={theme.primary} />
          </>
        );

      case 'YOUNG':
        // Small creature form
        return (
          <>
            <RadialGradient id="youngGradient" cx={center} cy={center} rx={radius * 0.8} ry={radius * 0.8}>
              <Stop offset="0%" stopColor={theme.glow} stopOpacity="1" />
              <Stop offset="100%" stopColor={theme.primary} stopOpacity="0.4" />
            </RadialGradient>
            <Circle cx={center} cy={center} r={radius * 0.8} fill="url(#youngGradient)" />
            {/* Eyes */}
            <Circle cx={center - 8} cy={center - 5} r={3} fill="#FFF" opacity={0.9} />
            <Circle cx={center + 8} cy={center - 5} r={3} fill="#FFF" opacity={0.9} />
          </>
        );

      case 'MATURE':
      case 'AWAKENED':
      case 'TRANSCENDENT':
        // Full form with complex aura
        return (
          <>
            <RadialGradient id="matureGradient" cx={center} cy={center} rx={radius} ry={radius}>
              <Stop offset="0%" stopColor={theme.glow} stopOpacity="1" />
              <Stop offset="30%" stopColor={theme.primary} stopOpacity="0.8" />
              <Stop offset="70%" stopColor={theme.secondary} stopOpacity="0.4" />
              <Stop offset="100%" stopColor={theme.primary} stopOpacity="0.1" />
            </RadialGradient>
            <Circle cx={center} cy={center} r={radius} fill="url(#matureGradient)" />
            {/* Crown/horns for higher phases */}
            {phase !== 'MATURE' && (
              <>
                <Circle cx={center - radius * 0.5} cy={center - radius * 0.3} r={4} fill={theme.glow} />
                <Circle cx={center + radius * 0.5} cy={center - radius * 0.3} r={4} fill={theme.glow} />
              </>
            )}
          </>
        );
    }
  };

  return renderPhaseShape();
};

function getPhaseMultiplier(phase: CompanionPhase): number {
  const multipliers: Record<CompanionPhase, number> = {
    EGG: 0.5,
    HATCHING: 0.7,
    YOUNG: 0.85,
    MATURE: 1,
    AWAKENED: 1.2,
    TRANSCENDENT: 1.5,
  };
  return multipliers[phase];
}

function getMoodEmoji(mood: CompanionMood): string {
  const emojis: Record<CompanionMood, string> = {
    SLEEPY: '😴',
    CONTENT: '😊',
    FOCUSED: '🎯',
    DETERMINED: '🔥',
    ECSTATIC: '✨',
    STRUGGLING: '😰',
    DANGER: '⚠️',
  };
  return emojis[mood];
}

