  canFreeze: boolean;
  /** Whether user has already frozen today */
  hasFrozenToday: boolean;
  /** Called when user taps to freeze */
  onFreeze: () => void;
  /** Loading state while freezing */
  isFreezing?: boolean;
  /** Compact mode for inline display */
  compact?: boolean;
