/**
 * StreakRiskBanner Component
 *
 * Appears at top of home screen when streak risk level is MEDIUM or higher.
 * Urgency increases: MEDIUM (amber) → HIGH (red) → CRITICAL (full-width alert).
 * Tapping navigates to session start.
 *
 * @phase 3C.1
 */

import React from 'react';
import { Pressable } from 'react-native';
import Animated, { useAnimatedStyle, withRepeat, withSequence, withTiming, withSpring } from 'react-native-reanimated';

import { Box } from '../../../components/primitives/Box';
import { Text } from '../../../components/primitives/Text';
import { useTheme } from '../../../theme';

export type StreakRiskLevel = 'NONE' | 'LOW' | 'MEDIUM' | 'HIGH' | 'CRITICAL';

export interface StreakRiskBannerProps {
  /** Current risk level */
  riskLevel: StreakRiskLevel;
  /** Hours remaining until streak breaks */
  hoursRemaining: number;
  /** Current streak days */
  streakDays: number;
  /** Suggested duration for session (pre-fill) */
  suggestedDuration: number;
  /** Navigate to session start */
  onStartSession: (duration: number) => void;
}

/**
 * Get risk configuration based on level
 */
function getRiskConfig(riskLevel: StreakRiskLevel, theme: ReturnType<typeof useTheme>['theme']) {
  switch (riskLevel) {
    case 'CRITICAL':
      return {
        bg: `${theme.colors.error.DEFAULT}30`,
        border: theme.colors.error.DEFAULT,
        text: theme.colors.error.DEFAULT,
        emoji: '🚨',
        label: 'CRITICAL',
        message: 'LAST CHANCE — Start now!',
        pulse: true,
      };
    case 'HIGH':
      return {
        bg: `${theme.colors.error.DEFAULT}20`,
        border: theme.colors.error.light,
        text: theme.colors.error.DEFAULT,
        emoji: '🔥',
        label: 'HIGH RISK',
        message: 'Streak at risk — act now',
        pulse: true,
      };
    case 'MEDIUM':
      return {
        bg: `${theme.colors.warning.DEFAULT}20`,
        border: theme.colors.warning.DEFAULT,
        text: theme.colors.warning.dark,
        emoji: '⏰',
        label: 'AT RISK',
        message: 'Start a session soon',
        pulse: false,
      };
    default:
      return null;
  }
}

/**
 * Streak risk banner
 */
export function StreakRiskBanner({ riskLevel, hoursRemaining, streakDays, suggestedDuration, onStartSession }: StreakRiskBannerProps): JSX.Element | null {
  const { theme } = useTheme();

  // Only show for MEDIUM or higher
  if (riskLevel === 'NONE' || riskLevel === 'LOW') {
    return null;
  }

  const config = getRiskConfig(riskLevel, theme);
  if (!config) {
    return null;
  }

  const pulseStyle = useAnimatedStyle(() => ({
    transform: [
      {
        scale: config.pulse ? withRepeat(withSequence(withTiming(1, { duration: 800 }), withTiming(1.02, { duration: 800 })), -1, true) : 1,
      },
    ],
    borderColor: config.pulse ? withRepeat(withSequence(withTiming(config.border, { duration: 500 }), withTiming(`${config.border}80`, { duration: 500 })), -1, true) : config.border,
  }));

  return (
    <Pressable onPress={() => onStartSession(suggestedDuration)} accessibilityLabel="Interactive control" accessibilityRole="button" accessibilityHint="Activates this control">
      <Animated.View
        style={[
          {
            marginHorizontal: theme.spacing[4],
            marginTop: theme.spacing[4],
            borderRadius: 12,
            borderWidth: 2,
            overflow: 'hidden',
          },
          pulseStyle,
        ]}
      >
        <Box bg={config.bg} p="md">
          {/* Main content */}
          <Box flexDirection="row" alignItems="center" gap="md">
            {/* Emoji indicator */}
            <Box width={44} height={44} borderRadius="full" bg={`${config.border}30`} justifyContent="center" alignItems="center">
              <Text fontSize={24}>{config.emoji}</Text>
            </Box>

            <Box flex={1}>
              {/* Label and time */}
              <Box flexDirection="row" alignItems="center" gap="sm" mb="xs">
                <Text variant="caption" color={config.text} fontWeight="700">
                  {config.label}
                </Text>
                <Text variant="caption" color="text.tertiary">
                  · {hoursRemaining}h left
                </Text>
              </Box>

              {/* Streak info */}
              <Text variant="body" color="text.primary" fontWeight="600">
                🔥 {streakDays}-day streak at risk
              </Text>

              {/* Urgency message */}
              <Text variant="bodySmall" color={config.text}>
                {config.message}
              </Text>
            </Box>

            {/* CTA arrow */}
            <Text fontSize={20} color={config.text}>
              →
            </Text>
          </Box>
        </Box>
      </Animated.View>
    </Pressable>
  );
}

