/**
 * Streak Risk Monitor Hook
 * 10/10 Quality: Real-time risk tracking, notifications, flame health UI
 */

import { useState, useCallback, useEffect, useRef } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import * as Sentry from '@sentry/react-native';
import { useAuth } from '../../../auth/hooks/useAuth';
import { useAnalytics } from '../../../analytics/hooks/useAnalytics';
import { eventBus } from '../../../events';

import { calculateStreakRisk, checkAndSendRiskNotifications, type StreakRiskStatus } from '../streak-risk-monitor';
import { fetchRiskStatusEnhanced, saveRiskStatusEnhanced, fetchStreakEnhanced } from '../repository-enhanced';
import { StreakRiskStatusSchema, type RiskLevel } from '../schemas-enhanced';

// ============================================================================
// Constants
// ============================================================================

const QUERY_KEYS = {
  riskStatus: (userId: string) => ['streaks', 'risk', userId],
  streak: (userId: string) => ['streaks', 'data', userId],
};

const RISK_CHECK_INTERVAL = 60 * 1000; // Check every minute
const STALE_TIME = 30 * 1000; // 30 seconds - risk data goes stale quickly

// ============================================================================
// Types
// ============================================================================

interface UseStreakRiskReturn {
  // Risk Data
  riskStatus: StreakRiskStatus | null;
  riskLevel: RiskLevel;
  hoursRemaining: number;
  minutesRemaining: number;
  flameHealthPercent: number;
  isAtRisk: boolean;
  isCritical: boolean;

  // Streak Data
  currentStreak: number;

  // Loading States
  isLoading: boolean;
  isChecking: boolean;
  isRefreshing: boolean;

  // Error States
  error: Error | null;

  // Actions
  checkRisk: () => Promise<void>;
  refresh: () => Promise<void>;

  // Retry
  retry: () => void;

  // UI Helpers
  flameColor: string;
  urgencyLabel: string;
  shouldShowWarning: boolean;
  shouldShowCritical: boolean;
  notificationSent: boolean;
}

// ============================================================================
// Flame Health Color Calculator
// ============================================================================

function getFlameColor(healthPercent: number): string {
  if (healthPercent > 75) {
    return '#4CAF50';
  } // Green - healthy
  if (healthPercent > 50) {
    return '#FF9800';
  } // Orange - warning
  if (healthPercent > 25) {
    return '#FF5722';
  } // Deep orange - danger
  return '#F44336'; // Red - critical
}

function getUrgencyLabel(riskLevel: RiskLevel): string {
  const labels: Record<RiskLevel, string> = {
    NONE: 'Safe',
    LOW: 'Stable',
    MEDIUM: 'Warning',
    HIGH: 'Urgent',
    CRITICAL: 'CRITICAL',
  };
  return labels[riskLevel];
}

// ============================================================================
// Hook
// ============================================================================

export function useStreakRisk(): UseStreakRiskReturn {
  const { user } = useAuth();
  const queryClient = useQueryClient();
  const { track } = useAnalytics();
  const userId = (user as any)?.id;

  const intervalRef = useRef<NodeJS.Timeout | null>(null);
  const [isChecking, setIsChecking] = useState(false);

  // ============================================================================
  // Queries
  // ============================================================================

  const {
    data: streakData,
    isLoading: isStreakLoading,
    error: streakError,
    refetch: refetchStreak,
  } = useQuery({
    queryKey: QUERY_KEYS.streak(userId || ''),
    queryFn: async () => {
      if (!userId) {
        return null;
      }

      const result = await fetchStreakEnhanced(userId);

      if (result.error) {
        throw result.error;
      }

      return result.data;
    },
    enabled: !!userId,
    staleTime: STALE_TIME,
    retry: 3,
  });

  const {
    data: cachedRiskStatus,
    isLoading: isRiskLoading,
    error: riskError,
    refetch: refetchRisk,
  } = useQuery({
    queryKey: QUERY_KEYS.riskStatus(userId || ''),
    queryFn: async () => {
      if (!userId) {
        return null;
      }

      const result = await fetchRiskStatusEnhanced(userId);

      if (result.error) {
        throw result.error;
      }

      if (!result.data) {
        return null;
      }

      return StreakRiskStatusSchema.parse(result.data);
    },
    enabled: !!userId,
    staleTime: STALE_TIME,
    retry: 3,
  });

  // ============================================================================
  // Real-time Risk Calculation
  // ============================================================================

  const riskStatus = (() => {
    if (!streakData) {
      return cachedRiskStatus || null;
    }

    // Calculate fresh risk status from streak data
    const freshRisk = calculateStreakRisk(streakData);

    // Merge with cached notifications sent
    if (cachedRiskStatus) {
      return {
        ...freshRisk,
        notificationsSent: cachedRiskStatus.notificationsSent,
      };
    }

    return freshRisk;
  })();

  // ============================================================================
  // Risk Check Mutation
  // ============================================================================

  const checkRiskMutation = useMutation({
    mutationFn: async () => {
      if (!userId || !streakData) {
        return null;
      }

      setIsChecking(true);

      try {
        // Calculate current risk
        const currentRisk = calculateStreakRisk(streakData);

        // Check and send notifications if needed
        await checkAndSendRiskNotifications(userId);

        // Persist risk status
        const saveResult = await (saveRiskStatusEnhanced as any)({
          ...currentRisk,
          lastUpdated: currentRisk.lastUpdated || Date.now(),
          notificationsSent: cachedRiskStatus?.notificationsSent || [],
        });

        if (saveResult.error) {
          throw saveResult.error;
        }

        // Track analytics
        if (currentRisk.isAtRisk) {
          track('streak_risk_detected', {
            riskLevel: currentRisk.riskLevel,
            hoursRemaining: currentRisk.hoursRemaining,
            streakDays: currentRisk.currentDays,
          });
        }

        return currentRisk;
      } finally {
        setIsChecking(false);
      }
    },
    onSuccess: (data) => {
      if (data && userId) {
        queryClient.setQueryData(QUERY_KEYS.riskStatus(userId), data);
      }
    },
    onError: (error) => {
      Sentry.captureException(error, {
        tags: { feature: 'streaks', hook: 'useStreakRisk', operation: 'checkRisk' },
      });
    },
  });

  // ============================================================================
  // Auto-check Interval
  // ============================================================================

  useEffect(() => {
    if (!userId) {
      return;
    }

    // Initial check
    checkRiskMutation.mutate();

    // Set up interval for periodic checks
    intervalRef.current = setInterval(() => {
      checkRiskMutation.mutate();
    }, RISK_CHECK_INTERVAL);

    return () => {
      if (intervalRef.current) {
        clearInterval(intervalRef.current);
      }
    };
  }, [userId, streakData?.currentDays]);

  // ============================================================================
  // Event Listeners
  // ============================================================================

  useEffect(() => {
    if (!userId) {
      return;
    }

    const handleStreakUpdated = () => {
      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.streak(userId) });
      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.riskStatus(userId) });
    };

    eventBus.subscribe('streak:updated', handleStreakUpdated);
    eventBus.subscribe('streak:session_completed', handleStreakUpdated);

    return () => {
      eventBus.unsubscribe('streak:updated', handleStreakUpdated);
      eventBus.unsubscribe('streak:session_completed', handleStreakUpdated);
    };
  }, [userId, queryClient]);

  // ============================================================================
  // Actions
  // ============================================================================

  const checkRisk = useCallback(async () => {
    await checkRiskMutation.mutateAsync();
  }, [checkRiskMutation]);

  const refresh = useCallback(async () => {
    await Promise.all([refetchStreak(), refetchRisk()]);
    await checkRisk();
  }, [refetchStreak, refetchRisk, checkRisk]);

  const retry = useCallback(() => {
    queryClient.invalidateQueries({ queryKey: QUERY_KEYS.streak(userId || '') });
    queryClient.invalidateQueries({ queryKey: QUERY_KEYS.riskStatus(userId || '') });
  }, [queryClient, userId]);

  // ============================================================================
  // Derived State
  // ============================================================================

  const isLoading = isStreakLoading || isRiskLoading;
  const error = (streakError || riskError || checkRiskMutation.error) as Error | null;
  const isRefreshing = checkRiskMutation.isPending;

  const flameColor = getFlameColor(riskStatus?.flameHealthPercent ?? 100);
  const urgencyLabel = getUrgencyLabel(riskStatus?.riskLevel || 'NONE');
  const shouldShowWarning = riskStatus?.riskLevel === 'MEDIUM' || riskStatus?.riskLevel === 'HIGH';
  const shouldShowCritical = riskStatus?.riskLevel === 'CRITICAL';
  const notificationSent = (riskStatus?.notificationsSent.length || 0) > 0;

  return {
    // Risk Data
    riskStatus,
    riskLevel: riskStatus?.riskLevel || 'NONE',
    hoursRemaining: riskStatus?.hoursRemaining ?? 24,
    minutesRemaining: riskStatus?.minutesRemaining ?? 1440,
    flameHealthPercent: riskStatus?.flameHealthPercent ?? 100,
    isAtRisk: riskStatus?.isAtRisk ?? false,
    isCritical: riskStatus?.isCritical ?? false,

    // Streak Data
    currentStreak: streakData?.currentDays ?? 0,

    // Loading States
    isLoading,
    isChecking,
    isRefreshing,

    // Error States
    error,

    // Actions
    checkRisk,
    refresh,

    // Retry
    retry,

    // UI Helpers
    flameColor,
    urgencyLabel,
    shouldShowWarning,
    shouldShowCritical,
    notificationSent,
  };
}

// ============================================================================
// Lightweight Hook for Flame Health Only
// ============================================================================

export function useFlameHealth(): {
  healthPercent: number;
  color: string;
  isAtRisk: boolean;
} {
  const { flameHealthPercent, flameColor, isAtRisk } = useStreakRisk();

  return {
    healthPercent: flameHealthPercent,
    color: flameColor,
    isAtRisk,
  };
}

/**
 * Micro-Interaction Engine
 * Makes every user action feel satisfying through haptics, sounds, and animations
