          <Card size="md" style={{ backgroundColor: theme.colors.background.secondary }}>
            <Box gap="md">
              <Text variant="bodySmall" color="text.secondary">
                Last {moodHistory.length} session{moodHistory.length !== 1 ? 's' : ''}
