                  ? 'primary.500'
                  : 'background.tertiary'
              }
              style={{
                opacity: isFuture ? 0.4 : 1,
                borderWidth: isActive ? 2 : 0,
                borderColor: isActive ? theme.colors.primary[400] : undefined,
              }}
