    hasScreenDarken: false,
    hasOrbitingParticles: false,
    label: 'RARE',
  },
  epic: {
    color: '#A855F7',
    glowColor: '#C084FC',
    bgColor: '#7C3AED',
    shakeIntensity: 8,
    shakeSpeed: 250,
    glowIntensity: 0.85,
    hasScreenDarken: true,
    hasOrbitingParticles: false,
    label: 'EPIC',
  },
  legendary: {
    color: '#F97316',
    glowColor: '#FDBA74',
    bgColor: '#EA580C',
    shakeIntensity: 12,
