/**
 * Animated Counter Component
 * Premium number display with smooth counting animations
 *
 * Features:
 * - Smooth counting animation between values
 * - Currency formatting with symbols
 * - Compact notation for large numbers
 * - Duration-based animation speed
 * - Custom prefix/suffix
 * - Color transitions on value change
 */

import React, { useEffect, useRef, useState } from 'react';
import { View, TextStyle, ViewStyle, StyleSheet } from 'react-native';
import Animated, {
  useSharedValue,
  useAnimatedStyle,
  useDerivedValue,
  withTiming,
  withSpring,
  runOnJS,
  interpolateColor,
  Easing,
} from 'react-native-reanimated';

import { Text } from '../../../components/primitives/Text';
import { useTheme } from '../../../theme';
import { createSheet } from '@/shared/ui/create-sheet';

// ============================================================================
// Types
// ============================================================================

export type CounterSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl' | 'hero';
export type CounterVariant = 'default' | 'currency' | 'percentage' | 'compact';

export interface AnimatedCounterProps {
  value: number;
  previousValue?: number;

  // Formatting
  variant?: CounterVariant;
  currency?: 'coins' | 'gems' | 'xp' | string;
  prefix?: string;
  suffix?: string;
  decimals?: number;

  // Appearance
  size?: CounterSize;
  color?: string;
  increaseColor?: string;
  decreaseColor?: string;
  style?: ViewStyle;
  textStyle?: TextStyle;

  // Animation
  duration?: number;
  useSpring?: boolean;
  springConfig?: {
    damping?: number;
    stiffness?: number;
  };

  // Features
  animateOnMount?: boolean;
  showTrendIndicator?: boolean;
  compactThreshold?: number;
  locale?: string;
}

// ============================================================================
// Utility Functions
// ============================================================================

function formatNumber(
  value: number,
  variant: CounterVariant,
  decimals: number,
  compactThreshold: number,
  locale: string
): string {
  'worklet';

  if (variant === 'compact' || (variant === 'currency' && Math.abs(value) >= compactThreshold)) {
    return Intl.NumberFormat(locale, {
      notation: 'compact',
      maximumFractionDigits: 1,
    }).format(value);
  }

  if (variant === 'percentage') {
    return `${value.toFixed(decimals)}%`;
  }

  return value.toLocaleString(locale, {
    minimumFractionDigits: decimals,
    maximumFractionDigits: decimals,
  });
}

function getCurrencySymbol(currency: string): string {
  const symbols: Record<string, string> = {
    coins: '🪙',
    gems: '💎',
    xp: '⭐',
    usd: '$',
    eur: '€',
    gbp: '£',
  };
  return symbols[currency] || currency;
}

function getSizeConfig(size: CounterSize): {
  fontSize: number;
  fontWeight: TextStyle['fontWeight'];
  trendSize: number;
} {
  const configs: Record<CounterSize, { fontSize: number; fontWeight: TextStyle['fontWeight']; trendSize: number }> = {
    xs: { fontSize: 12, fontWeight: '500', trendSize: 8 },
    sm: { fontSize: 14, fontWeight: '600', trendSize: 10 },
    md: { fontSize: 18, fontWeight: '700', trendSize: 12 },
    lg: { fontSize: 24, fontWeight: '700', trendSize: 14 },
    xl: { fontSize: 32, fontWeight: '800', trendSize: 16 },
    hero: { fontSize: 48, fontWeight: '900', trendSize: 20 },
  };
  return configs[size];
}

// ============================================================================
// Trend Indicator Component
// ============================================================================

const TrendIndicator: React.FC<{
  direction: 'up' | 'down' | 'neutral';
  size: number;
  color?: string;
}> = ({ direction, size, color }) => {
  const { theme } = useTheme();

  const trendColor = color || (direction === 'up'
    ? theme.colors.success.DEFAULT
    : direction === 'down'
    ? theme.colors.error.DEFAULT
    : theme.colors.text.tertiary);

  return (
    <View style={[styles.trendIndicator, { width: size, height: size }]}>
      <Text style={[styles.trendArrow, { color: trendColor, fontSize: size }]}>
        {direction === 'up' ? '▲' : direction === 'down' ? '▼' : '—'}
      </Text>
    </View>
  );
};

// ============================================================================
// Main Component
// ============================================================================

export const AnimatedCounter: React.FC<AnimatedCounterProps> = ({
  value,
  previousValue,
  variant = 'default',
  currency,
  prefix,
  suffix,
  decimals = 0,
  size = 'md',
  color,
  increaseColor,
  decreaseColor,
  style,
  textStyle,
  duration = 800,
  useSpring = false,
  springConfig = { damping: 15, stiffness: 150 },
  animateOnMount = true,
  showTrendIndicator = false,
  compactThreshold = 1000000,
  locale = 'en-US',
}) => {
  const { theme } = useTheme();
  const [displayValue, setDisplayValue] = useState(value);
  const previousRef = useRef(previousValue ?? value);

  const animatedValue = useSharedValue(animateOnMount ? 0 : value);
  const colorProgress = useSharedValue(0);

  const effectiveColor = color || theme.colors.text.primary;
  const effectiveIncreaseColor = increaseColor || theme.colors.success.DEFAULT;
  const effectiveDecreaseColor = decreaseColor || theme.colors.error.DEFAULT;

  // Determine trend
  const trend = value > previousRef.current ? 'up' :
                value < previousRef.current ? 'down' : 'neutral';

  // Animate value change
  useEffect(() => {
    const from = previousRef.current;
    const to = value;

    // Set initial value for animation
    animatedValue.value = from;
    previousRef.current = value;

    // Trigger color flash
    if (trend !== 'neutral') {
      colorProgress.value = 0;
      colorProgress.value = withTiming(1, { duration: 300 }, () => {
        colorProgress.value = withTiming(0, { duration: 500 });
      });
    }

    // Animate to new value
    if (useSpring) {
      animatedValue.value = withSpring(to, springConfig, (finished) => {
        if (finished) {
          runOnJS(setDisplayValue)(to);
        }
      });
    } else {
      animatedValue.value = withTiming(to, {
        duration,
        easing: Easing.out(Easing.cubic),
      }, (finished) => {
        if (finished) {
          runOnJS(setDisplayValue)(to);
        }
      });
    }

    // Update display value during animation
    const updateInterval = setInterval(() => {
      // This will be handled by the animated text component
    }, 16);

    return () => clearInterval(updateInterval);
  }, [value, duration, useSpring, springConfig, animatedValue, colorProgress, trend]);

  // Derived formatted value
  const formattedValue = useDerivedValue(() => {
    const current = animatedValue.value;
    return formatNumber(current, variant, decimals, compactThreshold, locale);
  });

  // Animated color based on trend
  const animatedTextStyle = useAnimatedStyle(() => ({
    color: interpolateColor(
      colorProgress.value,
      [0, 0.5, 1],
      [
        effectiveColor,
        trend === 'up' ? effectiveIncreaseColor : trend === 'down' ? effectiveDecreaseColor : effectiveColor,
        effectiveColor,
      ]
    ),
  }));

  const sizeConfig = getSizeConfig(size);
  const currencySymbol = currency ? getCurrencySymbol(currency) : null;

  // Build display string
  const getDisplayString = () => {
    const parts: string[] = [];

    if (prefix) {parts.push(prefix);}
    if (currencySymbol) {parts.push(currencySymbol);}

    const formatted = formatNumber(displayValue, variant, decimals, compactThreshold, locale);
    parts.push(formatted);

    if (suffix) {parts.push(suffix);}

    return parts.join('');
  };

  return (
    <View style={[styles.container, style]}>
      {showTrendIndicator && trend !== 'neutral' && (
        <TrendIndicator
          direction={trend}
          size={sizeConfig.trendSize}
          color={trend === 'up' ? effectiveIncreaseColor : effectiveDecreaseColor}
        />
      )}

      <Animated.Text
        style={[
          styles.counter,
          {
            fontSize: sizeConfig.fontSize,
            fontWeight: sizeConfig.fontWeight,
          },
          animatedTextStyle,
          textStyle,
        ]}
      >
        {getDisplayString()}
      </Animated.Text>
    </View>
  );
};

// ============================================================================
// Count Up/Count Down Hooks
// ============================================================================

export function useCountUp(
  end: number,
  duration: number = 1000,
  start: number = 0
): number {
  const [value, setValue] = useState(start);
  const startTimeRef = useRef<number | null>(null);

  useEffect(() => {
    startTimeRef.current = null;

    const animate = (timestamp: number) => {
      if (!startTimeRef.current) {
        startTimeRef.current = timestamp;
      }

      const elapsed = timestamp - startTimeRef.current;
      const progress = Math.min(elapsed / duration, 1);

      // Ease out cubic
      const easeProgress = 1 - Math.pow(1 - progress, 3);
      const current = start + (end - start) * easeProgress;

      setValue(current);

      if (progress < 1) {
        requestAnimationFrame(animate);
      }
    };

    requestAnimationFrame(animate);
  }, [end, duration, start]);

  return value;
}

export function useCounterAnimation(
  target: number,
  options: {
    duration?: number;
    delay?: number;
    onComplete?: () => void;
  } = {}
): number {
  const { duration = 800, delay = 0, onComplete } = options;
  const [value, setValue] = useState(0);
  const targetRef = useRef(target);

  useEffect(() => {
    targetRef.current = target;

    const startTimeout = setTimeout(() => {
      const startTime = Date.now();
      const startValue = value;

      const animate = () => {
        const elapsed = Date.now() - startTime;
        const progress = Math.min(elapsed / duration, 1);

        // Ease out cubic
        const easeProgress = 1 - Math.pow(1 - progress, 3);
        const current = Math.round(startValue + (targetRef.current - startValue) * easeProgress);

        setValue(current);

        if (progress < 1) {
          requestAnimationFrame(animate);
        } else {
          onComplete?.();
        }
      };

      requestAnimationFrame(animate);
    }, delay);

    return () => clearTimeout(startTimeout);
  }, [target, duration, delay, onComplete]);

  return value;
}

