/**
 * Reanimated 3 Hooks
 * Reusable animation logic using react-native-reanimated
 */

import { useEffect, useCallback } from 'react';
import {
  useSharedValue,
  useAnimatedStyle,
  withTiming,
  withSpring,
  withRepeat,
  withSequence,
  Easing,
  runOnJS,
  SharedValue,
} from 'react-native-reanimated';

interface AnimationConfig {
  type: 'fade' | 'slide' | 'scale' | 'shimmer' | 'pulse' | 'bounce';
  duration?: number;
  delay?: number;
  infinite?: boolean;
  toValue?: number;
   fromValue?: number;
}

interface AnimationResult {
  animatedValue: SharedValue<number>;
  animatedStyle: ReturnType<typeof useAnimatedStyle>;
  start: () => void;
  stop: () => void;
  reset: () => void;
}

export function useReanimated(config: AnimationConfig): AnimationResult {
  const animatedValue = useSharedValue(config.fromValue ?? 0);

  const getAnimation = useCallback(() => {
    const { type, duration = 300, toValue = 1, infinite = false } = config;

    switch (type) {
      case 'fade':
        return withTiming(toValue, {
          duration,
          easing: Easing.inOut(Easing.ease),
        });

      case 'slide':
        return withSpring(toValue, {
          damping: 12,
          stiffness: 100,
        });

      case 'scale':
        return withSpring(toValue, {
          damping: 10,
          stiffness: 100,
        });

      case 'shimmer':
        return withRepeat(
          withTiming(1, {
            duration,
            easing: Easing.linear,
          }),
          infinite ? -1 : 1,
          false
        );

      case 'pulse':
        return withRepeat(
          withSequence(
            withTiming(1, {
              duration,
              easing: Easing.inOut(Easing.ease),
            }),
            withTiming(0, {
              duration,
              easing: Easing.inOut(Easing.ease),
            })
          ),
          infinite ? -1 : 1,
          true
        );

      case 'bounce':
        return withSpring(toValue, {
          damping: 6,
          stiffness: 150,
        });

      default:
        return withTiming(toValue, { duration });
    }
  }, [config, animatedValue]);

  const start = useCallback(() => {
    animatedValue.value = getAnimation();
  }, [getAnimation, animatedValue]);

  const stop = useCallback(() => {
    animatedValue.value = animatedValue.value;
  }, [animatedValue]);

  const reset = useCallback(() => {
    animatedValue.value = config.fromValue ?? 0;
  }, [animatedValue, config.fromValue]);

  const animatedStyle = useAnimatedStyle(() => ({
    opacity: animatedValue.value,
    transform: [{ scale: animatedValue.value }],
  }));

  useEffect(() => {
    if (config.infinite) {
      const timer = setTimeout(() => start(), config.delay ?? 0);
      return () => clearTimeout(timer);
    }
    return undefined;
  }, [config.infinite, config.delay, start]);

  return { animatedValue, animatedStyle, start, stop, reset };
}

export function useFadeIn(duration = 300, delay = 0) {
  const opacity = useSharedValue(0);

  useEffect(() => {
    const timer = setTimeout(() => {
      opacity.value = withTiming(1, { duration });
    }, delay);
    return () => clearTimeout(timer);
  }, [opacity, duration, delay]);

  const animatedStyle = useAnimatedStyle(() => ({
    opacity: opacity.value,
  }));

  return animatedStyle;
}

export function useSlideIn(direction: 'up' | 'down' | 'left' | 'right' = 'up', distance = 50) {
  const translateValue = useSharedValue(
    direction === 'up' ? distance : direction === 'down' ? -distance : direction === 'left' ? distance : -distance
  );
  const opacity = useSharedValue(0);

  useEffect(() => {
    translateValue.value = withSpring(0, { damping: 12, stiffness: 100 });
    opacity.value = withTiming(1, { duration: 300 });
  }, [translateValue, opacity]);

  const animatedStyle = useAnimatedStyle(() => ({
    transform: [
      direction === 'left' || direction === 'right'
        ? { translateX: translateValue.value }
        : { translateY: translateValue.value },
    ],
    opacity: opacity.value,
  }));

  return animatedStyle;
}

export function usePressAnimation() {
  const scale = useSharedValue(1);

  const onPressIn = useCallback(() => {
    scale.value = withSpring(0.95, { damping: 10, stiffness: 200 });
  }, [scale]);

  const onPressOut = useCallback(() => {
    scale.value = withSpring(1, { damping: 10, stiffness: 200 });
  }, [scale]);

  const animatedStyle = useAnimatedStyle(() => ({
    transform: [{ scale: scale.value }],
  }));

  return { animatedStyle, onPressIn, onPressOut };
}

export function usePulseAnimation() {
  const pulse = useSharedValue(0.5);

  useEffect(() => {
    pulse.value = withRepeat(
      withSequence(
        withTiming(1, { duration: 1000 }),
        withTiming(0.5, { duration: 1000 })
      ),
      -1,
      true
    );
  }, [pulse]);

  return useAnimatedStyle(() => ({
    opacity: pulse.value,
  }));
}

export function useCountUp(targetValue: number, duration = 1000) {
  const animatedValue = useSharedValue(0);
  const [displayValue, setDisplayValue] = React.useState(0);

  useEffect(() => {
    animatedValue.value = withTiming(targetValue, {
      duration,
      easing: Easing.out(Easing.ease),
    }, (finished) => {
      if (finished) {
        runOnJS(setDisplayValue)(targetValue);
      }
    });
  }, [targetValue, duration, animatedValue]);

  return displayValue;
}

import React from 'react';
